import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import Seo from "@components/seo";
import Web3DevelopmentScreen from "@screens/web3-development";
import { useLocation } from "@reach/router";

const Web3SmartContractDevelopment = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Web3 Smart Contract Development Company", link: null },
  ];

  const { data } = props;
  const fileUrl =
    data?.web3SmartContractImg?.childImageSharp?.gatsbyImageData?.images
      ?.fallback?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const location = useLocation();
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "A Web3 smart contract development company builds secure, audited blockchain contracts to power DeFi, NFTs, and decentralized applications.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1343",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is a Web3 smart contract?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A Web3 smart contract is an autonomous program deployed on a blockchain, which will automatically enforce contracts once pre-stated conditions are satisfied, without a central authority.",
            },
          },
          {
            "@type": "Question",
            name: "What is a Web3 example?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "One typical example of Web3 is Uniswap, a decentralized exchange platform on which people transact crypto without going through a central authority using their wallets.",
            },
          },
          {
            "@type": "Question",
            name: "Is Web3 a cryptocurrency?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Web3 is not a cryptocurrency, no. Web3 is the future iteration of the internet, an internet that is based on blockchain technology and where users own their data and their assets. One of the components of the Web3 ecosystem is cryptocurrencies.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <Web3DevelopmentScreen db={db} />
      </main>
    </Layout_v2>
  );
};

export default Web3SmartContractDevelopment;

export const queryData = graphql`
  query MyQuery {
    web3SmartContractImg: file(
      relativePath: { eq: "web3-smart-contract.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "web3-smart-contract-development-company" } }
    ) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
